code.Python3:
#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it))
        out.append('YES' if ((N - M) & 1) == 0 else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

